insert into publications (
    id, title, abstract_text, year, type, status, doi, source, url,
    created_at, updated_at, validation_status, validation_comment, validated_at
) values
    (234, 'Microredes universitarias con energia solar distribuida para campus', 'Evaluacion de autoconsumo, almacenamiento y control local para reducir costes y mejorar resiliencia energetica en campus universitarios.', 2026, 'ARTICLE', 'PUBLISHED', '10.7777/energia.2026.234', 'Energia Aplicada Iberica', 'https://doi.org/10.7777/energia.2026.234', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (235, 'Gemelos digitales para planificacion de movilidad urbana electrica', 'Modelo urbano que combina estaciones, recarga y demanda horaria para simular decisiones de movilidad electrica y reparto modal.', 2025, 'ARTICLE', 'PUBLISHED', '10.7777/movilidad.2025.235', 'Movilidad y Ciudad', 'https://doi.org/10.7777/movilidad.2025.235', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (236, 'Almacenamiento energetico y respuesta de demanda en microredes municipales', 'Analisis de baterias estacionarias y senales de precio para coordinar edificios publicos dentro de microredes urbanas.', 2024, 'REPORT', 'PUBLISHED', null, 'Cuadernos de Energia Urbana', 'https://demo.example.es/microredes-municipales', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (237, 'Seguridad vial y priorizacion de autobuses electricos con datos en tiempo real', 'Integracion de trafico, sensores de via y regularidad de linea para priorizar transporte publico electrico manteniendo seguridad vial.', 2026, 'ARTICLE', 'ACCEPTED', '10.7777/movilidad.2026.237', 'Transporte Publico Inteligente', 'https://doi.org/10.7777/movilidad.2026.237', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (238, 'Integracion de infraestructura ciclista y energia solar en nodos intermodales', 'Diseno de nodos de movilidad que conectan bicicleta, autobuses y cubierta solar con lectura de gemelos digitales para operacion diaria.', 2023, 'CONFERENCE_PAPER', 'PUBLISHED', '10.7777/movilidad.2023.238', 'Congreso de Movilidad Sostenible', 'https://doi.org/10.7777/movilidad.2023.238', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (239, 'Sensores oceanicos para vigilar praderas marinas costeras', 'Uso de boyas y sondas de baja potencia para vigilar cambios en habitats costeros con impacto en biodiversidad marina.', 2025, 'ARTICLE', 'PUBLISHED', '10.7777/mar.2025.239', 'Ciencias Marinas Aplicadas', 'https://doi.org/10.7777/mar.2025.239', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
    (240, 'Robotica submarina para cartografia costera de alta resolucion', 'Plataforma de robotica submarina para adquirir mallas batimetricas y mosaicos visuales en tramos costeros complejos.', 2026, 'ARTICLE', 'PUBLISHED', '10.7777/mar.2026.240', 'Robotica Marina Iberica', 'https://doi.org/10.7777/mar.2026.240', now(), now(), 'VALIDATED', 'Demo seed data validated for public exploration.', now()),
